import { PortalResetModal } from './components/modals/PortalResetModal';
import { PrestigeTreeModal } from './components/modals/PrestigeTreeModal';
import { PetSpaceModal } from './components/modals/PetSpaceModal';
import { WeatherOverlays } from './components/WeatherOverlays';

function App() {
  const industry = useIndustry();
  const {
    heroes, boss, logs, gameSpeed, isSoundOn, souls, gold, divinity, pets, offlineGains,
    talents, artifacts, cards, constellations, keys, dungeonActive, dungeonTimer, resources, items,
    ultimateCharge, raidActive, tower, towerBoss, guild, voidMatter, voidActive, voidTimer, worldBossCooldownUntil,
    arenaRank, glory, quests, achievements, starlight, starlightUpgrades, autoSellRarity, arenaOpponents,
    victory,
    actions, partyDps, partyPower, combatEvents, theme, galaxy, monsterKills, gameStats,
    outerSpaceUnlocked,
    assignHero, showCampfire, setShowCampfire, setOuterSpaceUnlocked,
    activeExpeditions, activePotions, gardenPlots, setGardenPlots, setResources, setGold,
    marketStock, marketTimer, buyMarketItem,
    setItems, setAchievements, setBuildings,
    dungeonMastery,
    buyMasteryUpgrade,
    activeRift, riftTimer, exitRift,
    startRift, selectBlessing, riftState, // Update 81
    worldBoss, worldBossDamage, worldBossCanClaim, // Phase 6
    breedPets, // Phase 46
    territories, attackTerritory, // Phase 47
    weather, weatherTimer, // Phase 48
    buildings, upgradeBuilding, // Phase 53
    dailyQuests, dailyLoginClaimed, claimLoginReward, claimDailyQuest, checkDailies, // Phase 56
    winCardBattle, // Phase 55
    spaceship, upgradeSpaceship, // Phase 59
    dungeonState, moveDungeon, exitDungeon, handleDungeonEvent, descendDungeon, // Phase 61 & 83
    synergies, // Fixed: Destructured from useGame
    voidAscensions,
    formations, saveFormation, loadFormation, deleteFormation, // Update 74
    activeEvent,
    prestigeNodes, townVisited, triggerRebirth, guildQueue,
    setSouls, setDivinity, setStarlight, setHeroes, setGameSpeed, portalConfig, setPortalConfig,
    teamMorale, heroBonds, monuments, enshrineHero,
    patronDeity, deityLevel, deityFavor, deityEnergy, pledgeDeity, offerToDeity,
    runes, craftRune, socketRune, combineRunes, invokeWeather,
    bossTimer,
    roguelikeRun, emberFragments, roguelikeUpgrades, startRoguelikeRun, startPlanetaryRun, preparePlanetaryRun, clearPlanetaryExpedition, selectRoguelikeNode,
    performRoguelikeCombatAction, resolveRoguelikeRest, resolveRoguelikeEventOption,
    buyRoguelikeUpgrade, abandonRoguelikeRun,
    backroomsExplorers, backroomsOutpost, backroomsResources, backroomsLogs,
    recruitExplorer, sendExplorer, recallExplorer, restExplorer, useAlmondWater,
    upgradeOutpost, craftGear,
    backroomsUnlockedTechs, researchTech,
    backroomsFloor, backroomsFloorProgress, backroomsBossHp,
    fakePlayers,
    gvgWarState, startGvGWar, playerGvGAttack, currentTutorialIndex
  } = useGame();


  const [showShop, setShowShop] = useState(false);
  const [showTown, setShowTown] = useState(false); // Phase 53
  const [showIndustry, setShowIndustry] = useState(false);
  const [showCardBattle, setShowCardBattle] = useState(false); // Phase 55
  const [showDailyRewards, setShowDailyRewards] = useState(false); // Phase 56
  const [showMarket, setShowMarket] = useState(false);
  const [showMastery, setShowMastery] = useState(false);
  const [showRiftModal, setShowRiftModal] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showPrestigeTree, setShowPrestigeTree] = useState(false);
  const [showTavern, setShowTavern] = useState(false);
  // showCampfire managed by useGame (Phase 80)
  const [showStars, setShowStars] = useState(false);
  const [showBestiary, setShowBestiary] = useState(false);
  const [showDevTools, setShowDevTools] = useState(false);
  const [showStats, setShowStats] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showForge, setShowForge] = useState(false);
  const [showInventory, setShowInventory] = useState(false);
  const [showTower, setShowTower] = useState(false);
  const [showGuild, setShowGuild] = useState(false);
  const [showVoid, setShowVoid] = useState(false);
  const [showArena, setShowArena] = useState(false);
  const [showQuests, setShowQuests] = useState(false);
  const [showRunes, setShowRunes] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);
  const [showLog, setShowLog] = useState(false);
  const [showStarlight, setShowStarlight] = useState(false);
  const [showGalaxy, setShowGalaxy] = useState(false); // Phase Galaxy
  const [showWorldBoss, setShowWorldBoss] = useState(false); // Phase 6
  const [showStarForge, setShowStarForge] = useState(false);
  const [showLeaderboard, setShowLeaderboard] = useState(false);
  // PHASE 41

  const [showFishing, setShowFishing] = useState(false);
  const [showAlchemy, setShowAlchemy] = useState(false);
  const [showExpeditions, setShowExpeditions] = useState(false);
  const [showGarden, setShowGarden] = useState(false);
  const [showBreedingModal, setShowBreedingModal] = useState(false); // Phase 46
  const [showPetSpace, setShowPetSpace] = useState(false);
  const [showGuildWar, setShowGuildWar] = useState(false); // Phase 47
  const [showMuseum, setShowMuseum] = useState(false); // Phase 49
  const [showRoguelike, setShowRoguelike] = useState(false);
  const [showBackrooms, setShowBackrooms] = useState(false);
  const [showJourney, setShowJourney] = useState(false);
  const [bottomTab, setBottomTab] = useState<'heroes' | 'pets'>('heroes');

  const [importString, setImportString] = useState('');

  // Industry Tick Loop
  useEffect(() => {
    const interval = setInterval(() => {
      industry.processTick(1);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ignore if typing in an input
      if ((e.target as HTMLElement).tagName === 'INPUT' || (e.target as HTMLElement).tagName === 'TEXTAREA') return;

      if (e.key === 'Escape') {
        setShowShop(false); setShowTavern(false); setShowStars(false); setShowBestiary(false);
        setShowSettings(false); setShowForge(false); setShowInventory(false); setShowTower(false);
        setShowGuild(false); setShowVoid(false); setShowArena(false); setShowQuests(false);
        setShowRunes(false); setShowAchievements(false); setShowStarlight(false); setShowHelp(false);
        setShowGuild(false); setShowVoid(false); setShowArena(false); setShowQuests(false);
        setShowRunes(false); setShowAchievements(false); setShowStarlight(false); setShowHelp(false);
        setShowLog(false); setShowFishing(false); setShowAlchemy(false); setShowExpeditions(false);
      }
      if (e.key.toLowerCase() === 's') setShowShop(prev => !prev);
      if (e.key.toLowerCase() === 'i') setShowInventory(prev => !prev);
      if (e.key.toLowerCase() === 't') setShowTavern(prev => !prev);
      if (e.key.toLowerCase() === 'c') setShowBestiary(prev => !prev);
      if (e.key.toLowerCase() === 'h') setShowHelp(prev => !prev);
      if (e.key.toLowerCase() === 'g') setShowGuild(prev => !prev);
      if (e.key.toLowerCase() === 'r') setShowRunes(prev => !prev);
      if (e.key.toLowerCase() === 'a') setShowAchievements(prev => !prev);
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const getBackgroundClass = (level: number) => {
    if (riftState?.active) return 'bg-rift'; // Update 81
    if (dungeonActive) return 'bg-amber-500'; // Gold Vault
    if (voidActive) return 'bg-void animate-pulse'; // Void Dimension
    if (tower.active) return 'bg-slate-900'; // Tower
    if (level > 900) return 'bg-void';
    if (level > 40) return 'bg-lava';
    if (level > 20) return 'bg-ice';
    const biome = level % 3;
    if (biome === 1) return 'bg-forest';
    if (biome === 2) return 'bg-cave';
    return 'bg-dungeon';
  };

  const getThemeClasses = (t: string) => {
    switch (t) {
      case 'midnight': return 'bg-slate-900 border-blue-900 text-blue-100';
      case 'forest': return 'bg-green-950 border-green-800 text-green-100';
      case 'crimson': return 'bg-red-950 border-red-900 text-red-100';
      case 'void': return 'bg-purple-950 border-purple-900 text-purple-100';
      default: return 'bg-gray-800 border-gray-600 text-gray-200';
    }
  };

  // Phase 56: Auto-show Daily Rewards on new day/unclaimed
  // Phase 56: Auto-show Daily Rewards on new day/unclaimed
  useEffect(() => {
    // Check for reset on load
    if (checkDailies) checkDailies();

    // If not claimed, show modal
    if (dailyLoginClaimed === false) {
      setShowDailyRewards(true);
    }
  }, [dailyLoginClaimed]);

  const themeClass = getThemeClasses(theme);


  return (
    <div className={`h-screen w-full flex flex-col items-center justify-center p-2 relative overflow-hidden ${raidActive ? 'bg-red-900' : getBackgroundClass(boss.level)}`}>

      <div className="crt-overlay"></div>

      {/* WEATHER OVERLAYS */}
      <WeatherOverlays weather={weather} />

      {/* Game Container */}
      <div className={`w-full max-w-4xl h-full max-h-[900px] flex flex-col bg-opacity-95 border-4 rounded-lg shadow-2xl relative z-10 backdrop-blur-sm transition-colors duration-500 ${themeClass}`}>
        {/* TOWN EVENT WIDGET */}
        {activeEvent && <TownEventWidget event={activeEvent} actions={actions} onDismiss={actions.dismissEvent} />}

        <Header
          boss={boss} souls={souls} gold={gold} divinity={divinity} resources={resources}
          tower={tower} guild={guild} keys={keys} voidMatter={voidMatter}
          dungeonActive={dungeonActive}
          voidActive={voidActive} voidTimer={voidTimer}
          isSoundOn={isSoundOn} gameSpeed={gameSpeed} actions={{ ...actions, triggerRebirth, visitTown: () => { actions.visitTown(); setShowTown(true); } }}
          setShowShop={setShowShop} setShowTavern={setShowTavern} setShowStars={setShowStars}
          setShowForge={setShowForge} setShowInventory={setShowInventory} setShowBestiary={setShowBestiary}
          setShowStats={setShowStats} setShowTower={setShowTower} setShowGuild={setShowGuild}
          setShowSettings={setShowSettings} setShowVoid={setShowVoid} setShowArena={setShowArena}
          setShowQuests={setShowQuests} setShowDailyRewards={setShowDailyRewards}
          setShowRunes={setShowRunes} setShowAchievements={setShowAchievements}

          setShowStarlight={setShowStarlight} setShowGalaxy={setShowGalaxy}
          setShowLeaderboard={setShowLeaderboard} setShowHelp={setShowHelp}
          setShowFishing={setShowFishing} setShowAlchemy={setShowAlchemy}
          setShowExpeditions={setShowExpeditions} setShowGarden={setShowGarden}
          setShowRiftModal={setShowRiftModal}
          setShowGuildWar={setShowGuildWar} weather={weather} weatherTimer={weatherTimer}
          setShowMuseum={setShowMuseum} setShowTown={(v) => { if (v) actions.visitTown(); setShowTown(v); }}
          setShowCampfire={setShowCampfire} setShowStarForge={setShowStarForge}
          setShowWorldBoss={setShowWorldBoss}
          setShowDevTools={setShowDevTools}
          outerSpaceUnlocked={outerSpaceUnlocked}
          riftsUnlocked={backroomsUnlockedTechs.includes('rift_tech')}
          setShowPrestigeTree={setShowPrestigeTree}
          setShowPetSpace={setShowPetSpace}
          townVisited={townVisited}
           voidAscensions={voidAscensions}
          buildings={buildings}
          teamMorale={teamMorale}
          setShowRoguelike={setShowRoguelike}
          setShowBackrooms={setShowBackrooms}
          setShowJourney={setShowJourney}
        />

        <BattleArea
          boss={tower.active ? towerBoss : boss} dungeonActive={dungeonActive} dungeonTimer={dungeonTimer}
          ultimateCharge={ultimateCharge} pets={pets} actions={actions} artifacts={artifacts} heroes={heroes} partyDps={partyDps} partyPower={partyPower}
          combatEvents={combatEvents}
          synergies={synergies}
          bossTimer={bossTimer}
          tower={tower}
        />
        <div className="flex-1 flex flex-col min-h-0 bg-gray-800 border-t-4 border-gray-600">
          <div className="flex border-b border-gray-700 bg-gray-900/40 p-1 gap-1">
            <button
              onClick={() => setBottomTab('heroes')}
              className={`flex-1 py-2 rounded-lg font-bold text-xs uppercase tracking-wider transition-all duration-300 ${bottomTab === 'heroes' ? 'bg-amber-600 text-stone-950 font-black shadow-md' : 'text-stone-400 hover:text-stone-200 hover:bg-stone-900/40'}`}
            >
              👥 Heróis ({heroes.filter(h => h.unlocked).length}/{heroes.length})
            </button>
            <button
              onClick={() => setBottomTab('pets')}
              className={`flex-1 py-2 rounded-lg font-bold text-xs uppercase tracking-wider transition-all duration-300 ${bottomTab === 'pets' ? 'bg-amber-600 text-stone-950 font-black shadow-md' : 'text-stone-400 hover:text-stone-200 hover:bg-stone-900/40'}`}
            >
              🐾 Mascotes ({pets.length})
            </button>
          </div>
          <div className="flex-1 min-h-0 overflow-y-auto">
            {bottomTab === 'heroes' ? (
              <HeroList
                heroes={heroes}
                activeSynergies={synergies}
                actions={{ ...actions, formations, saveFormation, loadFormation, deleteFormation }}
                buildings={buildings}
                heroBonds={heroBonds}
              />
            ) : (
              <PetList
                pets={pets}
                actions={actions}
                gold={gold}
                souls={souls}
              />
            )}
          </div>
        </div>


        <GameLog logs={logs} onShowHistory={() => setShowLog(true)} />

        {/* Footer */}
        <div className="bg-gray-800 p-1 border-t-4 border-gray-600 flex justify-between items-center text-[10px] text-gray-500">
          <span>Terras Eternas do Abismo v2.8 - {divinity > 0 ? `Divinity Rank ${divinity}` : 'Mortal Realm'}</span>
          <div className="text-[10px] text-gray-600">Phase 21: Mastery Update</div>
        </div>

      </div>

      {/* MODALS RENDER */}
      <VictoryModal isOpen={victory} playTime={gameStats.playTime} ascensions={voidAscensions} onContinue={() => actions.setVictory(false)} />
      <LogModal isOpen={showLog} onClose={() => setShowLog(false)} logs={logs} />
      <HelpModal isOpen={showHelp} onClose={() => setShowHelp(false)} />
      <OfflineModal offlineGains={offlineGains} onClose={actions.closeOfflineModal} />
      <StarChartModal isOpen={showStars} onClose={() => setShowStars(false)} divinity={divinity} constellations={constellations} actions={actions} />
      <BestiaryModal isOpen={showBestiary} onClose={() => setShowBestiary(false)} monsterKills={monsterKills} cards={cards} />
      <SettingsModal isOpen={showSettings} onClose={() => setShowSettings(false)} actions={actions} importString={importString} setImportString={setImportString} autoSellRarity={autoSellRarity} theme={theme} />
      {showShop && <ShopModal isOpen={true} onClose={() => setShowShop(false)} souls={souls} talents={talents} boss={boss} actions={actions} />}
      {showTavern && <TavernModal heroes={heroes} gold={gold} tavernPurchases={gameStats.tavernPurchases || 0} heroPity={gameStats.heroPity || 0} petPity={gameStats.petPity || 0} summonTavern={actions.summonTavernLine} onClose={() => setShowTavern(false)} setGold={setGold} />}
      {showForge && <ForgeModal resources={resources} forgeUpgrade={actions.forgeUpgrade} onClose={() => setShowForge(false)} setResources={setResources} />}
      {showInventory && <InventoryModal isOpen={true} items={items} onClose={() => setShowInventory(false)} />}
      <TowerModal isOpen={showTower} onClose={() => setShowTower(false)} tower={tower} actions={actions} starlight={starlight} />
      <GuildModal isOpen={showGuild} onClose={() => setShowGuild(false)} guild={guild} gold={gold} actions={actions} guildQueue={guildQueue} />
      <VoidModal isOpen={showVoid} onClose={() => setShowVoid(false)} voidMatter={voidMatter} actions={actions} voidAscensions={voidAscensions} voidActive={voidActive} voidTimer={voidTimer} />
      <ArenaModal isOpen={showArena} onClose={() => setShowArena(false)} rank={arenaRank} glory={glory} heroes={heroes} opponents={arenaOpponents} onFight={actions.fightArena} />
      {showQuests && (
        <QuestModal
          quests={quests}
          onClose={() => setShowQuests(false)}
          onClaim={actions.claimQuest}
        />
      )}
      <RuneModal isOpen={showRunes} onClose={() => setShowRunes(false)} items={items} resources={resources} souls={souls} actions={{ craftRune, socketRune, combineRunes }} runes={runes || []} />
      {showAchievements && <AchievementsModal isOpen={showAchievements} achievements={achievements} stats={gameStats} onClose={() => setShowAchievements(false)} />}
      <StatisticsModal isOpen={showStats} onClose={() => setShowStats(false)} stats={gameStats} />
      <StarlightModal isOpen={showStarlight} onClose={() => setShowStarlight(false)} starlight={starlight} upgrades={starlightUpgrades} onBuy={actions.buyStarlightUpgrade} />
      <GalaxyModal
        isOpen={showGalaxy}
        onClose={() => setShowGalaxy(false)}
        galaxy={galaxy}
        onConquer={actions.attackSector}
        partyPower={partyPower}
        starlightUpgrades={starlightUpgrades}
        spaceship={spaceship}
        onUpgradeShip={upgradeSpaceship}
        towerFloor={tower.floor}
        voidAscensions={voidAscensions}
        onAscend={actions.ascendToVoid}
        onPreparePlanetaryRun={(sector) => {
          preparePlanetaryRun(sector.id, sector.name, sector.type as any, sector.level);
          setShowGalaxy(false);
          setShowRoguelike(true);
        }}
      />

      {/* PHASE 41 Modals */}
      <FishingModal
        isOpen={showFishing}
        onClose={() => setShowFishing(false)}
        fishCount={resources.fish || 0}
        legendaryCount={gameStats.legendaryFishCount || 0}
        setFish={() => actions.manualFish && actions.manualFish()}
        {...({ setGameStats: (actions as any).setGameStats } as any)}
      />

      <AlchemyModal isOpen={showAlchemy} onClose={() => setShowAlchemy(false)} resources={resources} activePotions={activePotions || []} brewPotion={actions.brewPotion} />

      <ExpeditionsModal isOpen={showExpeditions} onClose={() => setShowExpeditions(false)} activeExpeditions={activeExpeditions || []} heroes={heroes} startExpedition={actions.startExpedition} />

      <GardenModal isOpen={showGarden} onClose={() => setShowGarden(false)} plots={gardenPlots || []} setPlots={setGardenPlots} resources={resources} setResources={setResources} gold={gold} setGold={setGold} gardenSpeedMult={(patronDeity === 'gaya' ? 1.15 + (deityLevel - 1) * 0.05 : 1.0) * (backroomsUnlockedTechs.includes('cult_rotation') ? 1.10 : 1.0)} />

      <MarketModal isOpen={showMarket} onClose={() => setShowMarket(false)} stock={marketStock || []} buyItem={buyMarketItem} gold={gold} divinity={divinity} voidMatter={voidMatter} timer={marketTimer} />

      {/* RIFT OVERLAY */}
      {activeRift && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-red-900/90 border-2 border-red-500 text-white px-6 py-2 rounded-full z-50 flex items-center gap-4 shadow-[0_0_20px_rgba(220,38,38,0.5)] animate-pulse backdrop-blur-md">
          <span className="font-bold uppercase tracking-widest text-sm flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-red-500 animate-ping" />
            {activeRift.name}
          </span>
          <span className="font-mono text-xl text-yellow-300 font-bold">{riftTimer}s</span>
          <button
            onClick={() => exitRift(false)}
            className="bg-black/50 hover:bg-black/80 px-3 py-1 rounded text-xs border border-red-500/50 uppercase font-bold tracking-wider hover:text-red-400 transition-colors"
          >
            Abandon
          </button>
        </div>
      )}

      <RiftModal
        isOpen={showRiftModal}
        onClose={() => setShowRiftModal(false)}
        riftState={riftState}
        startRift={startRift}
        selectBlessing={selectBlessing}
        exitRift={exitRift}
        gameStats={gameStats}
      />
      {showBreedingModal && <BreedingModal isOpen={true} onClose={() => setShowBreedingModal(false)} pets={pets} breedPets={breedPets} gold={gold} />}

      {showGuildWar && (() => {
        const handleBombard = (id: string, weaponId: 'siege_catapult' | 'plasma_cannon') => {
          const currentCount = industry.inventory[weaponId] || 0;
          if (currentCount >= 1) {
            industry.setIndustryState(prev => ({
              ...prev,
              inventory: {
                ...prev.inventory,
                [weaponId]: prev.inventory[weaponId] - 1
              }
            }));
            const multiplier = weaponId === 'siege_catapult' ? 0.5 : 0.1;
            const weaponName = weaponId === 'siege_catapult' ? 'Catapulta de Cerco' : 'Canhão de Plasma';
            actions.bombardTerritory(id, multiplier, weaponName);
          }
        };
        return <GuildWarModal onClose={() => setShowGuildWar(false)} territories={territories} onAttack={attackTerritory} onUpgrade={actions.upgradeTerritory} onAdvanceMap={actions.advanceGuildWarMap} partyPower={partyPower} guild={guild} gold={gold} industryInventory={industry.inventory} onBombard={handleBombard} gvgWarState={gvgWarState} onStartGvG={() => startGvGWar(guild?.name || 'Sua Guilda')} onPlayerGvGAttack={playerGvGAttack} />;
      })()}

      {showPetSpace && <PetSpaceModal isOpen={true} onClose={() => setShowPetSpace(false)} pets={pets} gold={gold} souls={souls} onFeedGold={(id) => actions.feedPet('gold', id)} onFeedSouls={(id) => actions.feedPet('souls', id)} onBreed={() => { setShowPetSpace(false); setShowBreedingModal(true); }} />}
      <TownModal
        isOpen={showTown}
        onClose={() => setShowTown(false)}
        buildings={buildings}
        gold={gold}
        upgradeBuilding={upgradeBuilding}
        tower={tower}
        openIndustry={() => setShowIndustry(true)}
        openForge={() => setShowForge(true)}
        openFishing={() => setShowFishing(true)}
        openAlchemy={() => setShowAlchemy(true)}
        openExpeditions={() => setShowExpeditions(true)}
        openGarden={() => setShowGarden(true)}
        openRunes={() => { setShowRunes(true); setShowTown(false); }}
        heroes={heroes}
        monuments={monuments}
        enshrineHero={enshrineHero}
        patronDeity={patronDeity}
        deityLevel={deityLevel}
        deityFavor={deityFavor}
        deityEnergy={deityEnergy}
        pledgeDeity={pledgeDeity}
        offerToDeity={offerToDeity}
        souls={souls}
        divinity={divinity}
        invokeWeather={invokeWeather}
        resources={resources}
        openBackrooms={() => { setShowBackrooms(true); setShowTown(false); }}
        openGuild={() => { setShowGuild(true); setShowTown(false); }}
        openPetSpace={() => { setShowPetSpace(true); setShowTown(false); }}
        setBuildings={setBuildings}
        bossLevel={boss.level}
        voidAscensions={voidAscensions}
      />
      <IndustryModal isOpen={showIndustry} onClose={() => setShowIndustry(false)} industryState={industry} gold={gold} buyMachine={(cost, execute) => { if (gold >= cost) { setGold(g => g - cost); execute(); } }} />
      {showMuseum && <MuseumModal onClose={() => setShowMuseum(false)} heroes={heroes} pets={pets} cards={cards} items={items} onDuel={() => { setShowMuseum(false); setShowCardBattle(true); }} />}
      <CardBattleModal isOpen={showCardBattle} onClose={() => setShowCardBattle(false)} cards={cards} onWin={winCardBattle} stats={gameStats} />

      <LeaderboardModal isOpen={showLeaderboard} onClose={() => setShowLeaderboard(false)} entries={fakePlayers} currentPower={partyPower} />
      {dungeonActive && (
        <DungeonModal
          dungeon={dungeonState}
          onMove={(dx, dy) => {
            const event = moveDungeon(dx, dy);
            if (event) handleDungeonEvent(event);
          }}
          onDescend={descendDungeon}
          onExit={exitDungeon}
          onOpenMastery={() => setShowMastery(true)}
        />
      )}

      <DungeonMasteryModal
        isOpen={showMastery}
        onClose={() => setShowMastery(false)}
        mastery={dungeonMastery}
        tokens={resources.dungeonTokens || 0}
        buyUpgrade={buyMasteryUpgrade}
      />

      {activeEvent && (
        <TownEventWidget
          event={activeEvent}
          actions={actions}
          onDismiss={() => actions.dismissEvent()}
        />
      )}

      {showDailyRewards && (
        <DailyRewardsModal
          onClose={() => setShowDailyRewards(false)}
          dailyQuests={dailyQuests || []}
          gameStats={gameStats}
          claimLoginReward={claimLoginReward}
          claimDailyQuest={claimDailyQuest}
          dailyLoginClaimed={dailyLoginClaimed}
        />
      )}


      <StarForgeModal
        isOpen={showStarForge}
        onClose={() => setShowStarForge(false)}
        starFragments={resources.starFragments || 0}
        gold={gold}
        onCraft={actions.craftStarForgedItem}
      />
      <WorldBossModal
        isOpen={showWorldBoss}
        onClose={() => setShowWorldBoss(false)}
        worldBoss={worldBoss || null}
        personalDamage={worldBossDamage || 0}
        canClaim={worldBossCanClaim || false}
        cooldownUntil={worldBossCooldownUntil}
        attackAction={actions.attackWorldBoss}
        claimAction={actions.claimWorldBossReward}
      />
      <CampfireModal
        isOpen={showCampfire}
        onClose={() => setShowCampfire(false)}
        heroes={heroes}
        onAssign={assignHero}
      />
      {showDevTools && (
        <DevToolsModal
          isOpen={showDevTools}
          onClose={() => setShowDevTools(false)}
          setGold={setGold}
          setSouls={setSouls}
          setDivinity={setDivinity}
          setStarlight={setStarlight}
          setHeroes={setHeroes}
          setItems={setItems}
          setAchievements={setAchievements}
          setBuildings={setBuildings}
          setGameSpeed={setGameSpeed}
          gameSpeed={gameSpeed}
          setOuterSpaceUnlocked={setOuterSpaceUnlocked}
        />
      )}

      {/* PROGRESSION MODALS */}
      <PortalResetModal
        isOpen={!!portalConfig}
        title={portalConfig?.title}
        message={portalConfig?.message}
        warning={portalConfig?.warning}
        soulsGained={portalConfig?.soulsGained}
        rewardText={portalConfig?.rewardText}
        onConfirm={portalConfig?.onConfirm || (() => { })}
        onCancel={() => setPortalConfig(null)}
      />

      <PrestigeTreeModal
        isOpen={showPrestigeTree}
        onClose={() => setShowPrestigeTree(false)}
        souls={souls}
        prestigeNodes={prestigeNodes}
        onBuyNode={actions.buyPrestigeNode}
      />

      <RoguelikeModal
        isOpen={showRoguelike}
        onClose={() => {
          if (roguelikeRun.status === 'none') {
            clearPlanetaryExpedition();
          }
          setShowRoguelike(false);
        }}
        run={roguelikeRun}
        emberFragments={emberFragments}
        upgrades={roguelikeUpgrades}
        actions={{
          startRoguelikeRun: (classType) => {
            if (roguelikeRun.planetaryExpedition) {
              startPlanetaryRun(
                classType,
                roguelikeRun.planetaryExpedition.sectorId,
                roguelikeRun.planetaryExpedition.sectorName,
                roguelikeRun.planetaryExpedition.biome,
                roguelikeRun.planetaryExpedition.sectorLevel,
                galaxy
              );
            } else {
              startRoguelikeRun(classType);
            }
          },
          selectRoguelikeNode: selectRoguelikeNode,
          performRoguelikeCombatAction: performRoguelikeCombatAction,
          resolveRoguelikeRest: resolveRoguelikeRest,
          resolveRoguelikeEventOption: resolveRoguelikeEventOption,
          buyRoguelikeUpgrade,
          abandonRoguelikeRun
        }}
      />

      <BackroomsManagerModal
        isOpen={showBackrooms}
        onClose={() => setShowBackrooms(false)}
        currentTutorialIndex={currentTutorialIndex}
        explorers={backroomsExplorers}
        outpost={backroomsOutpost}
        resources={backroomsResources}
        logs={backroomsLogs}
        unlockedTechs={backroomsUnlockedTechs}
        floor={backroomsFloor}
        floorProgress={backroomsFloorProgress}
        bossHp={backroomsBossHp}
        actions={{
          recruitExplorer,
          sendExplorer,
          recallExplorer,
          restExplorer,
          useAlmondWater,
          upgradeOutpost,
          craftGear,
          researchTech
        }}
      />

      <JourneyModal
        isOpen={showJourney}
        onClose={() => setShowJourney(false)}
        state={{
          bossLevel: boss.level,
          highestFloor: tower.maxFloor || 1,
          voidAscensions,
          buildings,
          outerSpaceUnlocked,
          riftsUnlocked: backroomsUnlockedTechs.includes('rift_tech')
        }}
      />
    </div>
  );
}

export default App;
